create procedure [dbo].[CREATE_B2CSA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.B2CSA','U') IS NOT NULL  DROP TABLE B2CSA CREATE TABLE B2CSA ( [Original State Code] varchar(2) , [Type] varchar(2),  [Revised HSN] varchar(16),  [Revised Category] varchar(1),  [Recipient State Code] varchar(2),  [Total Taxable Value] decimal,  [IGST Rate] decimal, [IGST Amount] decimal, [CGST Rate] decimal, [CGST Amount] decimal, [SGST Rate] decimal, [SGST Amount] decimal, [CESS Rate] decimal, [CESS Amount] decimal, [Provisional Assessment] varchar(1), [E-Commerce GSTIN] varchar(1)) Set @Tablename='B2CSA' Select @Tablename 